#     formats: ipynb,R
#   kernelspec:
#     name: ir
#     display_name: R
#     language: R
# ---

# %% [markdown]
# Causal Inference Analysis using dagitty in R

# %%
suppressPackageStartupMessages({
  library(dagitty)
  library(data.table)
})

# Paths
 dag_path <- '/app/dag.txt'
 data_path <- '/app/data.csv'

# Load DAG specification
 dag_spec <- readLines(dag_path)
 g <- dagitty(paste(dag_spec, collapse='\n'))

# Load dataset
 dt <- fread(data_path)
 vars_in_data <- names(dt)

# Find minimal adjustment sets for T -> Y under back-door
 sets_raw <- adjustmentSets(g, exposure='T', outcome='Y', type='minimal')

# Convert sets to character vectors
 sets_list <- lapply(sets_raw, function(s) unlist(s))
 if (length(sets_list) == 0) sets_list <- list(character(0))

# Exclude descendants of T or Y; ensure variables are present in data and not T or Y
 desc_T <- descendants(g, 'T')
 desc_Y <- descendants(g, 'Y')
 is_valid_set <- function(s) {
   if (length(s) == 0) return(TRUE)
   # exclude descendants and ensure observed in data
   all(s %in% vars_in_data) && !any(s %in% c(desc_T, desc_Y, 'T', 'Y'))
 }
 valid_sets <- Filter(is_valid_set, sets_list)

# Write adjustment sets to file (one per line, comma-separated)
 con <- file('/app/adjustment_sets.txt', 'w')
 if (length(valid_sets) == 0) {
   writeLines('', con)
 } else {
   for (s in valid_sets) {
     writeLines(paste(s, collapse=', '), con)
   }
 }
 close(con)

# Choose one minimal adjustment set (first valid if any)
 adj <- if (length(valid_sets) > 0) valid_sets[[1]] else character(0)

# Fit OLS: Y ~ T + adj
 form_str <- paste('Y ~ T', if (length(adj) > 0) paste('+', paste(adj, collapse=' + ')) else '')
 model <- lm(as.formula(form_str), data=dt)
 ate <- unname(coef(model)[['T']])

# Save ATE as a single number
 writeLines(as.character(ate), con='/app/ate_result.txt')

# Display summary info
 print(sprintf('Selected adjustment set: %s', if (length(adj)>0) paste(adj, collapse=', ') else '(none)'))
 print(sprintf('ATE (coef of T): %0.10f', ate))
EOF
